// Panel query — adaptive across any time range
sum by (status_code) (
  rate(
    http_requests_total{
      job=~"$service",
      namespace=~"$namespace"
    }[$__rate_interval]
  )
)

// Loki equivalent — same adaptive contract
sum by (level) (
  rate({app=~"$service"} | json [$__interval])
)

import { initializeFaro, getWebInstrumentations } from '@grafana/faro-web-sdk';
import { TracingInstrumentation } from '@grafana/faro-web-tracing';
import { SessionInstrumentation } from '@grafana/faro-web-sdk';

initializeFaro({
  url: 'https://<faro-collector-host>/collect',
  app: { name: 'my-app', version: '1.0.0', environment: 'production' },
  instrumentations: [
    ...getWebInstrumentations({ captureConsole: true }),
    new TracingInstrumentation(),
    new SessionInstrumentation(),
  ],
  batching: { enabled: true, sendTimeout: 500 },
});

var (
    httpDuration = prometheus.NewHistogramVec(
        prometheus.HistogramOpts{
            Name:    "http_server_request_duration_seconds",
            Help:    "HTTP request latency in seconds.",
            Buckets: []float64{0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5},
        },
        []string{"method", "status_code", "handler"}, // bounded cardinality only
    )
    activeConns = prometheus.NewGauge(prometheus.GaugeOpts{
        Name: "http_server_active_connections",
        Help: "Current number of active HTTP connections.",
    })
    requestsTotal = prometheus.NewCounterVec(
        prometheus.CounterOpts{Name: "http_server_requests_total"},
        []string{"method", "status_code"},
    )
)

// Grafana panel JSON model snippet — RED error ratio + USE CPU utilization
{
  "panels": [
    {
      "title": "RED — Error Ratio",
      "type": "timeseries",
      "targets": [{
        "expr": "rate(http_requests_total{status=~\"5..\", service=\"$service\"}[5m]) / rate(http_requests_total{service=\"$service\"}[5m])",
        "legendFormat": "error ratio"
      }]
    },
    {
      "title": "USE — CPU Utilization",
      "type": "gauge",
      "targets": [{
        "expr": "1 - avg(rate(node_cpu_seconds_total{mode=\"idle\",instance=\"$instance\"}[5m]))",
        "legendFormat": "cpu util"
      }],
      "fieldConfig": {
        "defaults": {
          "thresholds": {
            "steps": [{"color": "green", "value": 0}, {"color": "yellow", "value": 0.8}, {"color": "red", "value": 0.9}]
          }
        }
      }
    }
  ]
}

// Grafana Alloy — strip high-cardinality labels before Mimir ingestion
prometheus.relabel "cardinality_guard" {
  // Drop unbounded labels; each unique value = a new TSDB series
  rule {
    action = "labeldrop"
    regex  = "user_id|request_id|session_id"
  }

  // Truncate pod names to an 8-char prefix to cap replica explosion
  rule {
    source_labels = ["pod"]
    target_label  = "pod"
    regex         = "([a-z0-9-]{1,8}).*"
    replacement   = "${1}"
  }

  forward_to = [prometheus.remote_write.mimir.receiver]
}

import http from 'k6/http';
import { check, fail } from 'k6';

export default function () {
  // Step 1: authenticate
  const loginRes = http.post('https://api.example.com/auth/token', {
    client_id: 'monitor',
    client_secret: __ENV.CLIENT_SECRET,
  });
  if (!check(loginRes, { 'login 200': (r) => r.status === 200 })) {
    fail('auth failed');
  }

  const token = loginRes.json('access_token');

  // Step 2: call protected endpoint
  const res = http.get('https://api.example.com/v1/status', {
    headers: { Authorization: `Bearer ${token}` },
  });
  check(res, {
    'status 200': (r) => r.status === 200,
    'latency < 500ms': (r) => r.timings.duration < 500,
    'healthy field true': (r) => r.json('healthy') === true,
  });
}

// grafana-alloy config.river — scrape CPU + memory profiles
pyroscope.scrape "app_scrape" {
  targets = [{
    "__address__" = "localhost:6060",
    "service_name" = "checkout-api",
  }]
  forward_to = [pyroscope.write.default.receiver]

  profiling_config {
    profile.process_cpu { enabled = true }
    profile.memory      { enabled = true }
    profile.goroutine   { enabled = true }
  }
}

pyroscope.write "default" {
  endpoint { url = "http://pyroscope:4040" }
}
